{
  "exercises": [
    {
      "sourceText": "Ich kaufe Brot.",
      "modelAnswer": "Je achète du pain.",
      "alternatives": [
        "J'achète du pain."
      ],
      "keyPoints": [
        "Present tense of 'kaufen' (acheter)",
        "Definite article 'du' for masculine singular nouns",
        "Basic vocabulary: Brot = pain"
      ]
    },
    {
      "sourceText": "Das Buch ist teuer.",
      "modelAnswer": "Le livre est cher.",
      "alternatives": [
        "Ce livre est cher."
      ],
      "keyPoints": [
        "Adjective 'teuer' → 'cher'",
        "Use of 'le' for masculine nouns",
        "Simple sentence structure with 'est'"
      ]
    },
    {
      "sourceText": "Ich habe Äpfel.",
      "modelAnswer": "J'ai des pommes.",
      "alternatives": [
        "J'ai des pommes."
      ],
      "keyPoints": [
        "Present tense of 'haben' → 'avoir'",
        "Plural form: Äpfel = pommes",
        "Use of 'des' for plural indefinite article"
      ]
    },
    {
      "sourceText": "Die Tasche ist klein.",
      "modelAnswer": "Le sac est petit.",
      "alternatives": [
        "Ce sac est petit."
      ],
      "keyPoints": [
        "Adjective 'klein' → 'petit'",
        "Masculine noun: Tasche = sac",
        "Use of 'est' for 'is'"
      ]
    },
    {
      "sourceText": "Ich suche Wasser.",
      "modelAnswer": "Je cherche de l'eau.",
      "alternatives": [
        "J'ai besoin d'eau."
      ],
      "keyPoints": [
        "Present tense of 'suchen' → 'chercher'",
        "Use of 'de l'' for uncountable nouns like 'eau'",
        "Basic verb + noun construction"
      ]
    }
  ]
}
